import { describe, it, expect, jest } from '@jest/globals';
import { AuthService } from '../src/auth';

jest.mock('../src/auth');
jest.mock('../src/database');

describe('AuthService', () => {
    it('should authenticate users', async () => {
        const mockAuth = jest.fn().mockResolvedValue({ id: 1, email: 'test@test.com' });
        (AuthService.prototype.login as jest.Mock).mockImplementation(mockAuth);
        const result = await AuthService.prototype.login('user', 'pass');
        expect(result.id).toBe(1);
    });
});
